  1→import { Injectable } from '@nestjs/common';
  2→
  3→import { OpensearchNeuralService } from '@modules/opensearch/opensearch-neural.service';
  4→
  5→import { LogExecution } from '@decorators/log-execution.decorator';
  6→
  7→import { NeuralSearchQueryDto } from '@dto/neural-search/neural-search-query.dto';
  8→import { NeuralSearchResponseDto } from '@dto/neural-search/neural-search-response.dto';
  9→
 10→@Injectable()
 11→export class NeuralSearchService {
 12→	constructor(private readonly opensearchNeuralService: OpensearchNeuralService) {}
 13→
 14→	@LogExecution({
 15→		paramFormatter: (params: [NeuralSearchQueryDto]) => ({
 16→			q: params[0].q,
 17→			tags: params[0].tags,
 18→			limit: params[0].limit,
 19→		}),
 20→		responseFormatter: (response: NeuralSearchResponseDto) => ({
 21→			total: response.total,
 22→		}),
 23→	})
 24→	async search({
 25→		query,
 26→	}: {
 27→		query: NeuralSearchQueryDto;
 28→	}): Promise<NeuralSearchResponseDto> {
 29→		const products = await this.opensearchNeuralService.searchProducts({
 30→			queryText: query.q,
 31→			...(query.limit !== undefined && { size: query.limit }),
 32→			...(query.tags?.length && { tags: query.tags }),
 33→		});
 34→
 35→		return {
 36→			query: query.q,
 37→			total: products.length,
 38→			products,
 39→		};
 40→	}
 41→
 42→	renderSearchPageHtml({
 43→		result,
 44→		tags,
 45→	}: {
 46→		result: NeuralSearchResponseDto | null;
 47→		tags: string[];
 48→	}): string {
 49→		const queryValue = result?.query ?? '';
 50→		const tagsValue = tags.join(', ');
 51→
 52→		const productCards = result
 53→			? result.products
 54→					.map(
 55→						(p) => `
 56→			<div style="border:1px solid #ddd;border-radius:8px;padding:12px;width:220px;text-align:center;background:#fff;display:flex;flex-direction:column;align-items:center;">
 57→				<img src="${p.style_card_image_url ?? ''}" alt="${p.name}" style="width:200px;height:200px;object-fit:contain;border-radius:4px;" onerror="this.src='data:image/svg+xml,<svg xmlns=%22http://www.w3.org/2000/svg%22 width=%22200%22 height=%22200%22><rect fill=%22%23eee%22 width=%22200%22 height=%22200%22/><text x=%2250%%22 y=%2250%%22 dominant-baseline=%22middle%22 text-anchor=%22middle%22 fill=%22%23999%22 font-size=%2214%22>No Image</text></svg>'"/>
 58→				<div style="margin-top:8px;font-weight:600;font-size:14px;min-height:40px;">${p.name}</div>
 59→				<div style="margin-top:4px;font-size:11px;color:#2563eb;font-weight:500;">Confidence: ${String(p.confidenceScore ?? 0)}%</div>
 60→				<div style="color:#555;font-size:12px;margin-top:4px;">${p.primary_category_name ?? ''}</div>
 61→				<div style="color:#666;font-size:11px;margin-top:2px;">${p.product_type ?? ''}</div>
 62→				<div style="color:#777;font-size:11px;margin-top:2px;">${p.manufacturer ?? ''}</div>
 63→				<div style="color:#888;font-size:11px;margin-top:2px;">${p.brand?.join(', ') ?? ''}</div>
 64→				${p.price ? `<div style="margin-top:6px;font-weight:700;font-size:15px;color:#16a34a;">$${String(p.price)}</div>` : ''}
 65→			</div>`,
 66→					)
 67→					.join('')
 68→			: '';
 69→
 70→		const resultsSection = result
 71→			? `<p style="margin:16px 0 8px;">Query: <strong>${result.query}</strong>${tags.length ? ` | Tags: <strong>${tags.join(', ')}</strong>` : ''} | Results: ${result.total}</p>
 72→			<div style="display:flex;flex-wrap:wrap;gap:16px;">${productCards}</div>`
 73→			: '';
 74→
 75→		return `<!DOCTYPE html>
 76→<html><head><meta charset="utf-8"><title>Neural Search</title></head>
 77→<body style="font-family:system-ui,sans-serif;margin:20px;background:#f5f5f5;">
 78→	<h2>Neural Search</h2>
 79→	<form id="searchForm" style="margin-bottom:16px;">
 80→		<div style="display:flex;gap:8px;margin-bottom:8px;">
 81→			<input id="searchInput" name="q" type="text" value="${queryValue}" placeholder="Describe what you're looking for..."
 82→				style="flex:1;max-width:500px;padding:10px 14px;font-size:15px;border:1px solid #ccc;border-radius:6px;outline:none;" />
 83→			<button type="submit"
 84→				style="padding:10px 20px;font-size:15px;background:#2563eb;color:#fff;border:none;border-radius:6px;cursor:pointer;">
 85→				Ask AI
 86→			</button>
 87→		</div>
 88→		<div style="display:flex;gap:8px;align-items:center;">
 89→			<input id="tagsInput" type="text" value="${tagsValue}" placeholder="Category tags (comma-separated, e.g. T-Shirts, Apparel)"
 90→				style="flex:1;max-width:500px;padding:8px 12px;font-size:13px;border:1px solid #ccc;border-radius:6px;outline:none;" />
 91→		</div>
 92→	</form>
 93→	<div id="results">${resultsSection}</div>
 94→	<script>
 95→		document.getElementById('searchForm').addEventListener('submit', function(e) {
 96→			e.preventDefault();
 97→			var q = document.getElementById('searchInput').value.trim();
 98→			if (!q) return;
 99→			var url = '/api/v1/neural-search/view?q=' + encodeURIComponent(q);
100→			var tagsRaw = document.getElementById('tagsInput').value.trim();
101→			if (tagsRaw) {
102→				var tags = tagsRaw.split(',').map(function(t) { return t.trim(); }).filter(Boolean);
103→				tags.forEach(function(tag) { url += '&tags=' + encodeURIComponent(tag); });
104→			}
105→			window.location.href = url;
106→		});
107→	</script>
108→</body></html>`;
109→	}
110→}
