  1→import { Injectable, Logger, OnModuleInit } from '@nestjs/common';
  2→import { Interval } from '@nestjs/schedule';
  3→
  4→import { IStylesMvBase } from '@modules/db/styles-mv/types/styles-mv.base.interface';
  5→import { EnvConfigService } from '@modules/env-config/env-config.service';
  6→import { OpensearchService } from '@modules/opensearch/opensearch.service';
  7→
  8→import {
  9→	NEURAL_SEARCH_LIMIT,
 10→	NEURAL_SEARCH_MAX_QUERY_LENGTH,
 11→} from '@constants/common.constant';
 12→import { OPENSEARCH_INDEX_NAME } from '@constants/env-variables.constant';
 13→import {
 14→	NEURAL_SEARCH_CONTRACTIONS,
 15→	NEURAL_SEARCH_KNOWN_BRANDS,
 16→	NEURAL_SEARCH_KNOWN_COLORS,
 17→	NEURAL_SEARCH_KNOWN_SIZES,
 18→} from '@constants/neural-search.constant';
 19→
 20→import { IOpensearchProduct } from '@interfaces/opensearch-product.interface';
 21→
 22→import { LogExecution } from '@decorators/log-execution.decorator';
 23→
 24→const MODEL_REFRESH_INTERVAL_MS = 5 * 60 * 1000;
 25→
 26→const MODEL_GROUP_NAME = 'neural-search-model-group';
 27→
 28→@Injectable()
 29→export class OpensearchNeuralService implements OnModuleInit {
 30→	private readonly logger = new Logger(OpensearchNeuralService.name);
 31→	private indexName: string;
 32→	private modelId: string | null = null;
 33→
 34→	constructor(
 35→		private readonly opensearchService: OpensearchService,
 36→		private readonly configService: EnvConfigService,
 37→	) {}
 38→
 39→	async onModuleInit(): Promise<void> {
 40→		this.indexName = this.configService.get<string>({ key: OPENSEARCH_INDEX_NAME });
 41→		await this.resolveModelId();
 42→	}
 43→
 44→	@Interval(MODEL_REFRESH_INTERVAL_MS)
 45→	async refreshModelId(): Promise<void> {
 46→		await this.resolveModelId();
 47→	}
 48→
 49→	private async resolveModelId(): Promise<void> {
 50→		try {
 51→			const modelId = await this.opensearchService.findDeployedModelId({
 52→				modelGroupName: MODEL_GROUP_NAME,
 53→			});
 54→
 55→			if (modelId && modelId !== this.modelId) {
 56→				const previousModelId = this.modelId;
 57→				this.modelId = modelId;
 58→				this.logger.log(`Model ID updated: ${previousModelId ?? 'none'} -> ${modelId}`);
 59→			} else if (!modelId) {
 60→				this.logger.warn(
 61→					'No deployed model found. Neural search will not work until bootstrap is run.',
 62→				);
 63→			}
 64→		} catch {
 65→			this.logger.warn('Failed to resolve model ID. OpenSearch may not be available.');
 66→		}
 67→	}
 68→
 69→	private getModelId(): string {
 70→		if (!this.modelId) {
 71→			throw new Error(
 72→				'Neural search model not available. Run: npm run cli:dev -- bootstrap-neural-search',
 73→			);
 74→		}
 75→		return this.modelId;
 76→	}
 77→
 78→	private detectBrand({ text }: { text: string }): string | null {
 79→		const sorted = [...NEURAL_SEARCH_KNOWN_BRANDS].sort((a, b) => b.length - a.length);
 80→		for (const brand of sorted) {
 81→			const escaped = brand.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
 82→			if (new RegExp(`\\b${escaped}\\b`, 'i').test(text)) {
 83→				return brand;
 84→			}
 85→		}
 86→		return null;
 87→	}
 88→
 89→	private detectColor({ text }: { text: string }): string | null {
 90→		const sorted = [...NEURAL_SEARCH_KNOWN_COLORS].sort((a, b) => b.length - a.length);
 91→		for (const color of sorted) {
 92→			const escaped = color.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
 93→			if (new RegExp(`\\b${escaped}\\b`, 'i').test(text)) {
 94→				return color;
 95→			}
 96→		}
 97→		return null;
 98→	}
 99→
100→	private readonly MEASUREMENT_UNITS_PATTERN =
101→		/\b\d+\s*(?:oz|ounce|ml|liter|litre|gal|gallon|inch|in|cm|mm|ft|foot|feet)\b/i;
102→
103→	private readonly PRICE_RANGE_PATTERNS: {
104→		pattern: RegExp;
105→		extract: (match: RegExpExecArray) => { min: number | null; max: number | null } | null;
106→	}[] = [
107→		{
108→			pattern: /\b(?:under|below|less\s+than|up\s+to)\s+\$(\d+(?:\.\d{1,2})?)/i,
109→			extract: (match) => {
110→				const max = parseFloat(match[1] ?? '');
111→				return isNaN(max) ? null : { min: null, max };
112→			},
113→		},
114→		{
115→			pattern: /\bfrom\s+\$(\d+(?:\.\d{1,2})?)\s+to\s+\$(\d+(?:\.\d{1,2})?)/i,
116→			extract: (match) => {
117→				const min = parseFloat(match[1] ?? '');
118→				const max = parseFloat(match[2] ?? '');
119→				return isNaN(min) || isNaN(max) ? null : { min, max };
120→			},
121→		},
122→		{
123→			pattern: /\$(\d+(?:\.\d{1,2})?)\s*[-–]\s*\$(\d+(?:\.\d{1,2})?)/i,
124→			extract: (match) => {
125→				const min = parseFloat(match[1] ?? '');
126→				const max = parseFloat(match[2] ?? '');
127→				return isNaN(min) || isNaN(max) ? null : { min, max };
128→			},
129→		},
130→		{
131→			pattern: /\$(\d+(?:\.\d{1,2})?)\s+to\s+\$(\d+(?:\.\d{1,2})?)/i,
132→			extract: (match) => {
133→				const min = parseFloat(match[1] ?? '');
134→				const max = parseFloat(match[2] ?? '');
135→				return isNaN(min) || isNaN(max) ? null : { min, max };
136→			},
137→		},
138→		{
139→			pattern: /\b(?:over|above|more\s+than)\s+\$(\d+(?:\.\d{1,2})?)/i,
140→			extract: (match) => {
141→				const min = parseFloat(match[1] ?? '');
142→				return isNaN(min) ? null : { min, max: null };
143→			},
144→		},
145→		{
146→			pattern: /\b(?:around|about|~)\s*\$(\d+(?:\.\d{1,2})?)/i,
147→			extract: (match) => {
148→				const price = parseFloat(match[1] ?? '');
149→				return isNaN(price)
150→					? null
151→					: { min: Math.round(price * 0.7), max: Math.round(price * 1.3) };
152→			},
153→		},
154→		{
155→			pattern: /\$(\d+(?:\.\d{1,2})?)/,
156→			extract: (match) => {
157→				const price = parseFloat(match[1] ?? '');
158→				return isNaN(price)
159→					? null
160→					: { min: Math.round(price * 0.7), max: Math.round(price * 1.3) };
161→			},
162→		},
163→	];
164→
165→	private detectPriceRange({
166→		text,
167→	}: {
168→		text: string;
169→	}): { min: number | null; max: number | null } | null {
170→		for (const { pattern, extract } of this.PRICE_RANGE_PATTERNS) {
171→			const match = pattern.exec(text);
172→			if (match) {
173→				return extract(match);
174→			}
175→		}
176→		return null;
177→	}
178→
179→	private stripContractions({ text }: { text: string }): string {
180→		let result = text;
181→		for (const contraction of NEURAL_SEARCH_CONTRACTIONS) {
182→			result = result.replace(new RegExp(`\\b${contraction}\\b`, 'gi'), '');
183→		}
184→		return result;
185→	}
186→
187→	private detectSize({ text }: { text: string }): string | null {
188→		const cleanedText = this.stripContractions({
189→			text: text.replace(this.MEASUREMENT_UNITS_PATTERN, ''),
190→		});
191→		const sorted = [...NEURAL_SEARCH_KNOWN_SIZES].sort((a, b) => b.length - a.length);
192→		for (const size of sorted) {
193→			const escaped = size.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
194→			if (new RegExp(`\\b${escaped}\\b`, 'i').test(cleanedText)) {
195→				return size;
196→			}
197→		}
198→		return null;
199→	}
