201→	private readonly GENDER_PRODUCT_TYPE_MAP: {
202→		pattern: RegExp;
203→		productTypes: string[];
204→	}[] = [
205→		{
206→			pattern: /\b(women|woman|womens|women's|female|ladies|lady|girls|girl's)\b/i,
207→			productTypes: ["Women's"],
208→		},
209→		{
210→			pattern: /\b(men|man|mens|men's|male|guys|guy)\b/i,
211→			productTypes: ['Unisex'],
212→		},
213→		{
214→			pattern: /\b(youth|kids|kid|children|child|toddler|infant|baby|juvenile)\b/i,
215→			productTypes: ['Youth'],
216→		},
217→	];
218→
219→	private detectGenderProductTypes({ text }: { text: string }): string[] | null {
220→		const productTypes: string[] = [];
221→
222→		for (const { pattern, productTypes: types } of this.GENDER_PRODUCT_TYPE_MAP) {
223→			if (pattern.test(text)) {
224→				productTypes.push(...types);
225→			}
226→		}
227→
228→		return productTypes.length > 0 ? productTypes : null;
229→	}
