231→	private readonly PRICE_LEVEL_MAP: { pattern: RegExp; levels: number[] }[] = [
232→		{
233→			pattern:
234→				/\b(cheap|budget|affordable|inexpensive|low[\s-]cost|economical|bargain|value|discount|basic|entry[\s-]level)\b/i,
235→			levels: [1],
236→		},
237→		{
238→			pattern:
239→				/\b(mid[\s-]range|midrange|moderate|average|standard|medium|middle|reasonable|fair price|mid price)\b/i,
240→			levels: [2],
241→		},
242→		{
243→			pattern:
244→				/\b(premium|luxury|high[\s-]end|expensive|upscale|top[\s-]tier|deluxe|elite|designer|exclusive|finest)\b/i,
245→			levels: [3],
246→		},
247→	];
248→
249→	private detectPriceLevels({ text }: { text: string }): number[] | null {
250→		const levels: number[] = [];
251→
252→		for (const { pattern, levels: priceLevels } of this.PRICE_LEVEL_MAP) {
253→			if (pattern.test(text)) {
254→				levels.push(...priceLevels);
255→			}
256→		}
257→
258→		return levels.length > 0 ? levels : null;
259→	}
