261→	private sanitizeQuery({ text }: { text: string }): string {
262→		return text
263→			.trim()
264→			.replace(/<[^>]*>/g, ' ')
265→			.replace(/[\x00-\x1F\x7F]/g, ' ')
266→			.replace(/[^a-zA-Z0-9\s\-'&]/g, ' ')
267→			.replace(/\s{2,}/g, ' ')
268→			.substring(0, NEURAL_SEARCH_MAX_QUERY_LENGTH)
269→			.trim();
270→	}
271→
272→	private readonly QUERY_SYNONYMS: [RegExp, string][] = [
273→		[/\btshirt(s)?\b/gi, 't-shirt$1'],
274→		[/\bt shirt(s)?\b/gi, 't-shirt$1'],
275→		[/\bv[\s-]?neck\b/gi, 'v-neck'],
276→		[/\bcrew[\s-]?neck\b/gi, 'crewneck'],
277→		[/\blong[\s-]?sleeve(s)?\b/gi, 'long-sleeve$1'],
278→		[/\bshort[\s-]?sleeve(s)?\b/gi, 'short-sleeve$1'],
279→		[/\bpolo[\s-]?shirt(s)?\b/gi, 'polo t-shirt$1'],
280→		[/\bsweat[\s-]?shirt(s)?\b/gi, 'sweatshirt$1'],
281→		[/\bsweat[\s-]?pant(s)?\b/gi, 'sweatpant$1'],
282→		[/\bzip[\s-]?up(s)?\b/gi, 'zip-up$1'],
283→		[/\bhalf[\s-]?zip(s)?\b/gi, 'half-zip$1'],
284→		[/\btote[\s-]?bag(s)?\b/gi, 'tote bag$1'],
285→		[/\bdri[\s-]?fit\b/gi, 'dri-fit'],
286→		[/\bslim[\s-]?fit\b/gi, 'slim fit'],
287→		[/\btank[\s-]?top(s)?\b/gi, 'tank top$1'],
288→	];
289→
290→	private normalizeQuery({ text }: { text: string }): string {
291→		let normalized = text.toLowerCase().trim();
292→
293→		for (const [pattern, replacement] of this.QUERY_SYNONYMS) {
294→			normalized = normalized.replace(pattern, replacement);
295→		}
296→
297→		return normalized;
298→	}
