387→	@LogExecution({ logParams: false, logResponse: false })
388→	async bulkIndexProducts({
389→		indexName,
390→		styles,
391→	}: {
392→		indexName: string;
393→		styles: IStylesMvBase[];
394→	}): Promise<{ indexed: number; errors: number }> {
395→		if (styles.length === 0) {
396→			return { indexed: 0, errors: 0 };
397→		}
398→
399→		const documents = styles.map((style) =>
400→			this.transformStyleToOpensearchProduct({ style }),
401→		);
402→
403→		return this.opensearchService.bulkIndex({ indexName, documents });
404→	}
405→
406→	@LogExecution({
407→		paramFormatter: (params: [{ queryText: string; size: number; tags?: string[] }]) => ({
408→			queryText: params[0].queryText,
409→			size: params[0].size,
410→			tags: params[0].tags,
411→		}),
412→		responseFormatter: (response: IOpensearchProduct[]) => ({
413→			totalResults: response.length,
414→		}),
415→	})
416→	async searchProducts({
417→		queryText,
418→		size = NEURAL_SEARCH_LIMIT,
419→		tags,
420→	}: {
421→		queryText: string;
422→		size?: number;
423→		tags?: string[];
424→	}): Promise<IOpensearchProduct[]> {
425→		const sanitizedQuery = this.sanitizeQuery({ text: queryText });
426→		const normalizedQuery = this.normalizeQuery({ text: sanitizedQuery });
427→		const genderProductTypes = this.detectGenderProductTypes({ text: sanitizedQuery });
428→		const priceLevels = this.detectPriceLevels({ text: sanitizedQuery });
429→		const brand = this.detectBrand({ text: sanitizedQuery });
430→		const detectedColor = this.detectColor({ text: sanitizedQuery });
431→		const detectedSize = this.detectSize({ text: sanitizedQuery });
432→		const detectedPriceRange = this.detectPriceRange({ text: queryText });
433→
434→		const baseFilters: object[] = [{ term: { status: 'active' } }];
435→
436→		const genderBoosts: object[] = genderProductTypes
437→			? [{ terms: { product_type: genderProductTypes } }]
438→			: [];
439→
440→		const priceBoosts: object[] =
441→			priceLevels?.map((level) => ({
442→				term: { price_level: { value: level } },
443→			})) ?? [];
444→
445→		const brandBoosts: object[] = brand ? [{ terms: { brand: [brand] } }] : [];
446→
447→		const categoryBoosts: object[] = tags?.length
448→			? [
449→					{ terms: { primary_category_name: tags } },
450→					{ terms: { broad_category_names: tags } },
451→					{ terms: { sub_category_names: tags } },
452→				]
453→			: [];
454→
455→		const colorBoosts: object[] = detectedColor
456→			? [
457→					{
458→						nested: {
459→							path: 'colors',
460→							query: {
461→								wildcard: {
462→									'colors.name': {
463→										value: `*${detectedColor.toLowerCase()}*`,
464→										case_insensitive: true,
465→									},
466→								},
467→							},
468→						},
469→					},
470→				]
471→			: [];
472→
473→		const unitPriceBoosts: object[] = detectedPriceRange
474→			? [
475→					{
476→						range: {
477→							price: {
478→								...(detectedPriceRange.min !== null && { gte: detectedPriceRange.min }),
479→								...(detectedPriceRange.max !== null && { lte: detectedPriceRange.max }),
480→								boost: 2,
481→							},
482→						},
483→					},
484→				]
485→			: [];
486→
487→		const sizeBoosts: object[] = detectedSize
488→			? [
489→					{
490→						wildcard: {
491→							sizes: { value: `*${detectedSize.toLowerCase()}*`, case_insensitive: true },
492→						},
493→					},
494→				]
495→			: [];
496→
497→		const hits = await this.opensearchService.search({
498→			indexName: this.indexName,
499→			searchPipeline: 'hybrid-search-pipeline',
500→			body: {
501→				size,
502→				min_score: 0.4,
503→				query: {
504→					hybrid: {
505→						queries: [
506→							{
507→								bool: {
508→									should: [
509→										...priceBoosts,
510→										...brandBoosts,
511→										...categoryBoosts,
512→										...genderBoosts,
513→										...colorBoosts,
514→										...sizeBoosts,
515→										...unitPriceBoosts,
516→									],
517→									filter: baseFilters,
518→								},
519→							},
520→							{
521→								neural: {
522→									product_embedding: {
523→										query_text: normalizedQuery,
524→										model_id: this.getModelId(),
525→										k: size * 5,
526→										filter: { bool: { filter: baseFilters } },
527→									},
528→								},
529→							},
530→						],
531→					},
532→				},
533→				collapse: { field: 'product_id' },
534→				_source: { excludes: ['product_embedding', 'combined_text_for_embedding'] },
535→			},
536→		});
537→
538→		const maxScore = Math.max(...hits.map((hit) => hit._score), 1);
539→
540→		return hits.map((hit) => {
541→			const product = hit._source as IOpensearchProduct;
542→			const imageUrl = detectedColor
543→				? this.resolveColorImageUrl({ product, colorName: detectedColor })
544→				: null;
545→
546→			return {
547→				...product,
548→				_id: hit._id,
549→				confidenceScore: Math.round((hit._score / maxScore) * 100),
550→				...(imageUrl !== null && { style_card_image_url: imageUrl }),
551→			};
552→		});
553→	}
554→
555→	private resolveColorImageUrl({
556→		product,
557→		colorName,
558→	}: {
559→		product: IOpensearchProduct;
560→		colorName: string;
561→	}): string | null {
562→		if (!product.colors?.length) return null;
563→
564→		const lowerColor = colorName.toLowerCase();
565→		const match = product.colors.find((c) => c.name.toLowerCase() === lowerColor);
566→
567→		if (match?.image_url) return match.image_url;
568→
569→		const partialMatch = product.colors.find((c) =>
570→			c.name.toLowerCase().includes(lowerColor),
571→		);
572→
573→		return partialMatch?.image_url ?? null;
574→	}
575→
576→	private normalizeCondensedFeatures({
577→		condensedFeatures,
578→	}: {
579→		condensedFeatures: unknown;
580→	}): string[] | null {
581→		if (condensedFeatures === null || condensedFeatures === undefined) {
582→			return null;
583→		}
584→
585→		if (typeof condensedFeatures === 'string') {
586→			return [condensedFeatures];
587→		}
588→
589→		if (Array.isArray(condensedFeatures)) {
590→			return condensedFeatures.map(String);
591→		}
592→
593→		if (typeof condensedFeatures === 'object') {
594→			return Object.values(condensedFeatures).flatMap((value: unknown) =>
595→				Array.isArray(value) ? value.map(String) : [String(value)],
596→			);
597→		}
598→
599→		return [JSON.stringify(condensedFeatures)];
600→	}
601→
602→	private buildCombinedTextForEmbedding({ style }: { style: IStylesMvBase }): string {
603→		const normalizedCondensedFeatures = this.normalizeCondensedFeatures({
604→			condensedFeatures: style.condensed_features,
605→		});
606→		const priceLvlMap: Record<string, string> = {
607→			1: 'Budget',
608→			2: 'Mid-range',
609→			3: 'Premium',
610→		};
611→		const mappedPriceLevel: string | null =
612→			style.price_level && priceLvlMap[String(style.price_level)]
613→				? (priceLvlMap[String(style.price_level)] ?? null)
614→				: (priceLvlMap['2'] ?? null);
615→
616→		const parts: string[] = [
617→			...(style.name ? [this.cleanText({ text: style.name })] : []),
618→			...(style.product_type ? [this.cleanText({ text: style.product_type })] : []),
619→			...(mappedPriceLevel ? [`Price lvl: ${mappedPriceLevel}`] : []),
620→			...(style.brand?.length
621→				? [`Brand: ${this.cleanText({ text: style.brand[0] })}`]
622→				: []),
623→			...(normalizedCondensedFeatures?.length
624→				? [this.cleanText({ text: normalizedCondensedFeatures.join(', ') })]
625→				: []),
626→			...(style.style_type ? [this.cleanText({ text: style.style_type })] : []),
627→			...(style.primary_category_name
628→				? [`Category: ${this.cleanText({ text: style.primary_category_name })}`]
629→				: []),
630→			...(style.manufacturer
631→				? [`From: ${this.cleanText({ text: style.manufacturer })}`]
632→				: []),
633→			...(style.sub_category_names?.length
634→				? [
635→						`Subcategories: ${this.cleanText({ text: style.sub_category_names.join(', ') })}`,
636→					]
637→				: []),
638→			...(style.decoration_method
639→				? [`Decoration: ${this.cleanText({ text: style.decoration_method })}`]
640→				: []),
641→			...(style.features
642→				? [`Features: ${this.cleanText({ text: style.features })}`]
643→				: []),
644→		];
645→
646→		const combinedText = parts.filter(Boolean).join('. ');
647→
648→		this.logger.debug(
649→			`Combined text length for style_id ${style.style_id}: ${combinedText.length} characters`,
650→		);
651→
652→		return combinedText;
653→	}
654→
655→	private extractPrice({
656→		prices,
657→	}: {
658→		prices: IOpensearchProduct['default_unit_prices'];
659→	}): number | null {
660→		if (!prices?.length) return null;
661→		const first = prices[0];
662→		if (!first) return null;
663→		const parsed = parseFloat(first.price);
664→		return isNaN(parsed) ? null : parsed;
665→	}
666→
667→	private cleanText({ text }: { text: string | null | undefined }): string {
668→		if (!text) return '';
669→		return text
670→			.replace(/\r\n|\r|\n/g, ' ')
671→			.replace(/[*#]+\s?/g, '')
672→			.replace(/<[^>]*>/g, '')
673→			.replace(/\s{2,}/g, ' ')
674→			.trim();
675→	}
676→
677→	private transformStyleToOpensearchProduct({
678→		style,
679→	}: {
680→		style: IStylesMvBase;
681→	}): IOpensearchProduct {
682→		return {
683→			_id: style._id,
684→			style_id: style.style_id,
685→			product_id: style.product_id,
686→			name: style.name ?? '',
687→			features: style.features,
688→			general_comments: style.general_comments,
689→			decoration_method: style.decoration_method,
690→			manufacturer: style.manufacturer,
691→			primary_category_id: style.primary_category_id,
692→			primary_category_name: style.primary_category_name,
693→			product_type: style.product_type,
694→			style_type: style.style_type,
695→			broad_category_names: style.broad_category_names,
696→			sub_category_names: style.sub_category_names,
697→			minimum_quantity: style.minimum_quantity,
698→			min_qty: style.min_qty,
699→			default_quote_qty: style.default_quote_qty,
700→			sizes: style.sizes,
701→			turn_time: style.turn_time,
702→			rush_turn_time: style.rush_turn_time,
703→			no_minimum: style.no_minimum ? 1 : 0,
704→			price_level: style.price_level,
705→			rating_score: style.rating_score !== null ? Number(style.rating_score) : null,
706→			rating_count: style.rating_count,
707→			default_unit_prices: style.default_unit_prices,
708→			price: this.extractPrice({ prices: style.default_unit_prices }),
709→			colors: style.colors,
710→			style_card_image_url: style.style_card_image_url,
711→			link: style.link,
712→			brand: style.brand,
713→			condensed_features: this.normalizeCondensedFeatures({
714→				condensedFeatures: style.condensed_features,
715→			}),
716→			material: style.material,
717→			status: style.status,
718→			created_at:
719→				style.created_at instanceof Date
720→					? style.created_at.toISOString()
721→					: String(style.created_at),
722→			updated_at:
723→				style.updated_at instanceof Date
724→					? style.updated_at.toISOString()
725→					: String(style.updated_at),
726→			deleted_at: style.deleted_at
727→				? style.deleted_at instanceof Date
728→					? style.deleted_at.toISOString()
729→					: String(style.deleted_at)
730→				: null,
731→			combined_text_for_embedding: this.buildCombinedTextForEmbedding({ style }),
732→		};
733→	}
734→}
